const payload = $json.body ?? $json;
const diet = String(payload.diet ?? 'balanced').trim() || 'balanced';
const calories = Number(payload.calories ?? 2000);
const allergiesRaw = payload.allergies ?? [];
const allergies = Array.isArray(allergiesRaw)
  ? allergiesRaw.map((a) => String(a).trim()).filter(Boolean)
  : String(allergiesRaw).split(',').map((a) => a.trim()).filter(Boolean);

if (!Number.isFinite(calories) || calories < 900 || calories > 6000) {
  throw new Error('calories must be between 900 and 6000');
}

const promptLines = [
  'Generate a 1-day meal plan in JSON only.',
  'User profile:',
  '- diet: ' + diet,
  '- target_calories: ' + calories,
  '- allergies: ' + (allergies.length ? allergies.join(', ') : 'none'),
  '',
  'Return strict JSON with this exact shape:',
  '{',
  '  "diet": "string",',
  '  "target_calories": number,',
  '  "allergies": ["string"],',
  '  "meals": [',
  '    {"name":"Breakfast","items":[{"food":"string","portion":"string","calories":number,"protein_g":number,"carbs_g":number,"fat_g":number}]},',
  '    {"name":"Lunch","items":[{"food":"string","portion":"string","calories":number,"protein_g":number,"carbs_g":number,"fat_g":number}]},',
  '    {"name":"Dinner","items":[{"food":"string","portion":"string","calories":number,"protein_g":number,"carbs_g":number,"fat_g":number}]},',
  '    {"name":"Snack","items":[{"food":"string","portion":"string","calories":number,"protein_g":number,"carbs_g":number,"fat_g":number}]}',
  '  ],',
  '  "daily_totals":{"calories":number,"protein_g":number,"carbs_g":number,"fat_g":number},',
  '  "notes":["string"]',
  '}',
  'No markdown fences.'
];

return [{ json: { diet, calories, allergies, prompt: promptLines.join('\n') } }];

const raw = $json.output ?? $json.text ?? '';
if (typeof raw !== 'string' || !raw.trim()) {
  throw new Error('AI response is empty');
}

const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  const start = cleaned.indexOf('{');
  const end = cleaned.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) {
    throw new Error('Unable to parse meal plan JSON from AI output');
  }
  parsed = JSON.parse(cleaned.slice(start, end + 1));
}

return [{ json: { ok: true, meal_plan: parsed } }];
